mapper.select:
SELECT * FROM (
    SELECT ROWNUM AS RNUM, B.* FROM (
        SELECT b.*,
               (SELECT img_name 
                FROM (SELECT img_name FROM BOARD_IMG WHERE b_no = b.b_no ORDER BY img_no ASC) 
                WHERE ROWNUM = 1) AS THUMBIMG
        FROM BOARD b
        ORDER BY B_NO DESC
    ) B
) WHERE RNUM BETWEEN #{pageBegin} AND #{pageEnd}

mapper.update:
UPDATE BOARD 
SET B_TITLE = #{b_title}, B_CONTENT = #{b_content} 
WHERE B_NO = #{b_no}
